function LxRoleCtrl:OnRolePowerChange(newPower)
    local roleInfo = ModuleCenter.Role.roleInfo
    local oldPower = -1
    if roleInfo then
        oldPower = tonumber(roleInfo.power)
    end
    ModuleCenter.Role:SetRolePower(newPower)
    --CtrlCenter.City:RefreshMonsterHUD()
    newPower = tonumber(newPower)
    if oldPower >= 0 and newPower > oldPower then
        self:SaveRolePowerChange(oldPower,newPower)
        if not self._isPowerOpen then
            self._isPowerOpen = CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.Power)
        end
        if self._isPowerOpen then
            local data = {
                oldRolePower = oldPower,
                newRolePower = newPower,
            }
            local uiKey = UiNames.FloatUpInfo
            --if IsOpenPanel(uiKey) then
            --    RefreshPanel(uiKey, data)
            --else
                ShowPanel(uiKey, data)
            --end
        end
    end
    FireEvent(EventNames.ROLE_ATTR_CHANGED)
end

function LxRoleCtrl:SaveRolePowerChange(oldPower,newPower)
    self._oldRolePower = oldPower
    self._newRolePower = newPower
end

function LxRoleCtrl:GetRolePowerChange()
    local oldPower = self._oldRolePower
    local newPower = self._newRolePower
    self._oldRolePower = nil
    self._newRolePower = nil
    return oldPower, newPower
end

