    local oldVipExp = -1

    --local oldLv =  -1
    local oldName = ""
    local oldGender = -1
    local oldSignature = ""
    if roleInfo then
        --oldLv = roleInfo.level
        oldVipLv = roleInfo.vipLevel
        oldVipExp = roleInfo.vipExp
        oldGender = roleInfo.gender
        oldSignature = roleInfo.signature
    end
    ModuleCenter.Role:SetRoleInfo(pb.roleInfo)
    --local newLv = ModuleCenter.Role:GetRoleLevel()
    local newVipLv = ModuleCenter.Role:GetRoleVipLevel() or 0
    local newVipExp = ModuleCenter.Role:GetRoleVipExp() or 0
    local newName = ModuleCenter.Role:GetRoleName()
    local newGender = ModuleCenter.Role:GetRoleGender() or 0
    local newSignature = ModuleCenter.Role:GetSignature()
    --- T3 去掉了等级这个概念
    --if oldLv >= 0 and newLv > oldLv then
    --    CtrlCenter.Game:TryPopPanel(UiNames.RoleLvup, {oldLv = oldLv, newLv = newLv})
    --    FireEvent(EventNames.ROLE_LEVEL_CHANGE)
    --    if gLxSdkImpl then
    --        gLxSdkImpl:CallMethod(SdkMethod.DoRoleLevelUp)
    --    end
    --end

    if oldVipLv >= 0 and newVipLv > oldVipLv then
        ShowPanel(UiNames.VipUpgrade)
        FireEvent(EventNames.VIP_LEVEL_UPDATE, oldVipLv , newVipLv)
    end

    if oldVipExp >= 0 and newVipExp > oldVipExp then
        --ShowPanel(UiNames.VipUpgrade)
        FireEvent(EventNames.VIP_EXP_UPDATE)
    end
    if oldName ~= newName then
        FireEvent(EventNames.ROLE_RENAME)
    end
    if oldGender ~= newGender then
        FireEvent(EventNames.ROLE_CHANGE_SEX)
    end
    if oldSignature ~= newSignature then
        FireEvent(EventNames.ROLE_CHANGE_SIGNATURE)
    end
end

