---@param roleInfo LxRoleInfo|LxRoleSimpleInfo
function LxRoleCtrl:GetRoleSignatureStr(roleInfo)
    local signature = roleInfo.signature
    if signature == nil or signature == "" then
        local gender = roleInfo.gender
        local genderRef = GameTable.RoleGenderRef[gender]
        if genderRef then
            local roleText = genderRef.roleText
            if roleText and roleText > 0 then
                signature = I18nText(roleText)
            end
        end
    end
    return signature
end

