--- 获取个性装扮 返回的数据 table[一级页签][二级页签]
---table = {
--- [一级页签] = {
---     [二级页签] = {}
--- }
---}
function LxRoleCtrl:GetRoleCardRefList()
    if #self._roleCardRefList > 0 then
        return self._roleCardRefList
    end
    local cardList = GameTable.RoleCardRef
    local typeRefList = GameTable.RoleTypeRef
    for _, v in pairs(cardList) do
        if not self._roleCardRefList[v.type] then
            self._roleCardRefList[v.type] = {type = v.type}
        end
        if not self._roleCardRefList[v.type][v.page] then
            self._roleCardRefList[v.type][v.page] = {}
        end
        table.insert(self._roleCardRefList[v.type][v.page], v)
    end
    table.sort(self._roleCardRefList, function(a, b)
        return typeRefList[a.type].sort < typeRefList[b.type].sort
    end)
    return self._roleCardRefList
end
--- @param type number 一级页签refId
function LxRoleCtrl:GetRoleCardPageByType(type)
    local pageRef = GameTable.RolePageRef
    local showList = {}
    for _, v in pairs(pageRef) do
        if v.type == type then
            local cardList = self:GetRoleCardList(type, v.refId)
            if not table.isempty(cardList) then
                table.insert(showList, v)
            end
        end
    end
    table.sort(showList, function(a, b) return a.refId < b.refId end)
    return showList
end
--- @param type number 一级页签
--- @param page number 二级页签
--- @param isFilter boolean 是否筛选已拥有的
--- 获取 当前页签展示的装扮列表
function LxRoleCtrl:GetRoleCardList(type, page, isFilter)
    local roleCardRefList = self:GetRoleCardRefList()
    local showList = {}
    local dataList = roleCardRefList[type][page] or {}
    if isFilter then
        for _, v in ipairs(dataList) do
            local cardInfo = ModuleCenter.Role:GetRoleCardInfo(v.refId)
            local isUnlock = not table.isempty(cardInfo)
            if isUnlock then
                table.insert(showList, v)
            end
        end
    else
        showList = dataList
    end
    table.sort(showList, function(a, b)
        local cardInfoA = ModuleCenter.Role:GetRoleCardInfo(a.refId)
        local isUnlockA = not table.isempty(cardInfoA)
        local cardInfoB = ModuleCenter.Role:GetRoleCardInfo(b.refId)
        local isUnlockB = not table.isempty(cardInfoB)
        if isUnlockA and isUnlockB then
            return a.sort < b.sort
        else
            if isUnlockA then
                return true
            elseif isUnlockB then
                return false
            end
        end
        return a.sort < b.sort
    end)
    return showList
end
