--- 根据属性列表 返回一个多个属性以逗号拼接的字符串 如 {1=10, 3=40} ===> '攻击：10，生命：40'
function LxRoleCtrl:GetAttrShowStr(attrList)
    if table.isempty(attrList) then
        return ""
    end
    local curAttrList = LxDataHelper.ParseAttrList(attrList)
    local attrStr = ""
    for i, v in ipairs(curAttrList) do
        local attrName = LxDataHelper.GetCombatAttributeName(v.refId)
        local curValue = LxDataHelper.ConvertAttrValue(v.refId, v.value)
        local endStr = i ~= #curAttrList and " " or ""
        attrStr = attrStr .. I18nText(8456, attrName, curValue) .. endStr

    end
    return attrStr
end


--- 获取所有已拥有的个性装扮 排序好的属性列表
function LxRoleCtrl:GetRoleCardAttr()
    local cardInfoList = ModuleCenter.Role:GetRoleCardInfoMap()
    local refList = GameTable.RoleCardRef
    local attrList = {}
    local sortList = {}
    for _, v in pairs(cardInfoList) do
        local ref = refList[v.refId]
        if not table.isempty(ref.attributes) then
            local curAttrList = LxDataHelper.ParseAttrList(ref.attributes)
            for _, v2 in ipairs(curAttrList) do
                if not attrList[v2.refId] then
                    local _t = {}
                    _t.value = 0
                    _t.refId = v2.refId
                    _t.sort = LxDataHelper.GetCombatAttributeSort(v2.refId)
                    attrList[v2.refId] = _t
                end
                attrList[v2.refId].value = attrList[v2.refId].value + v2.value
            end
        end
    end
    for _, v in pairs(attrList) do
        table.insert(sortList, v)
    end
    table.sort(sortList, function(a, b) return a.sort < b.sort end)
    return sortList
end

--- 获取对应主城皮肤
--- @param refId number 皮肤id
--- @param type number 1 城内 2城外
function LxRoleCtrl:GetCitySkinRes(refId, type)
    local ref = GameTable.RoleCityRef[refId]
    local lv = ModuleCenter.Building:GetBuildingLvl(BuildingType.HuoLu)
    local resList
    if type == 1 then-- 城内资源
        resList = string.split(ref.insideCity, "|")
    else
        resList= string.split(ref.iconSpine, "|")
    end
    local _t = string.split(resList[1], "=")
    local resName = _t[3]
    for _, v in ipairs(resList) do
        local _temp = string.split(v, "=")
        if lv >= checknumber(_temp[2]) then
            resName = _temp[3]
        end
    end
    return resName
end
