---首次登录（通过剧情和引导是否为空判断）
function LxRoleCtrl:IsFirstLogin()
    --剧情
    local startStoryType = ModuleCenter.Story:GetStartStoryType()
    local resetId = CtrlCenter.Story:GetNewbieResetStep(ModuleCenter.Story:GetLastSceneId())
    if(startStoryType > 0 or resetId > 0)then
        return false
    end
    --指引
    local guideList = ModuleCenter.Guide:GetFinishedGuideIds()
    local count = 0
    for i, v in ipairs(guideList) do
        count = count + 1
    end
    if(count > 0)then
        return false
    end
    return true
end
