function LxRoleCtrl:GetCityMonsters()
    local res = {}
    local monsters = ModuleCenter.Role:GetCityMonster()
    if(monsters == nil or monsters.monster == nil)then
        return res
    end

    for i, v in ipairs(monsters.monster) do
        table.insert(res,v)
    end
    return res
end
function LxRoleCtrl:GetMonsterById(id)
    local monsters = self:GetCityMonsters()
    for i, v in pairs(monsters) do
        if(v == id)then
            return v;
        end
    end
    return nil
end
function LxRoleCtrl:GetMonsterIndex(id)
    local monster = self:GetCityMonsters()
    for i, v in pairs(monster) do
        if(v == id)then
            return i;
        end
    end
    return 0
end


